import { useState, useEffect } from "react";
import { BrowserRouter, Routes, Route, useLocation } from "react-router-dom";
import { ThemeProvider } from "./context/ThemeContext";
import { LangProvider }  from "./context/LangContext";
import { AuthProvider }  from "./context/AuthContext";
import ProtectedRoute    from "./components/ProtectedRoute";
import Navbar            from "./components/Navbar/Navbar";
import Title            from "./components/Title/Title";

import HomePage          from "./pages/HomePage/HomePage";
import LoginPage         from "./pages/AuthPage/LoginPage";
import RegisterPage      from "./pages/AuthPage/RegisterPage";
import HistoryPage       from "./pages/HistoryPage/HistoryPage";
import ProfilePage       from "./pages/ProfilePage/ProfilePage";
import RealtimePage      from "./pages/01_RealtimePage/RealtimePage";
import ClassifyPage      from "./pages/02_ClassifyPage/ClassifyPage";
import DetectPage        from "./pages/03_DetectPage/DetectPage";

import "./App.css";

function Header() {
  const location = useLocation();

  const getTitle = (path) => {
    switch (path) {
      case "/":
        return "Home";
      case "/realtime":
        return "Real-time Cell Analysis";
      case "/classify":
        return "Cell Classification";
      case "/detect":
        return "Cell Counting";
      case "/history":
        return "History";
      case "/profile":
        return "Profile";
      default:
        return "Time Cell";
    }
  };

  return (
    <header className="app-header">
      <h2>{getTitle(location.pathname)}</h2>
    </header>
  );
}

export default function App() {
  const [expanded, setExpanded] = useState(false);

  useEffect(() => {
    const handler = (e) => setExpanded(e.detail.expanded);
    window.addEventListener("sidebarToggle", handler);
    return () => window.removeEventListener("sidebarToggle", handler);
  }, []);

  return (
    <ThemeProvider>
      <LangProvider>
        <AuthProvider>
          <BrowserRouter>
            <Navbar />
            <Title />
            <main className={`page-content ${expanded ? "sidebar-expanded" : ""}`}>
              <Routes>
                <Route path="/"         element={<HomePage />} />
                <Route path="/login"    element={<LoginPage />} />
                <Route path="/register" element={<RegisterPage />} />
                <Route path="/realtime" element={<RealtimePage />} />
                <Route path="/classify" element={<ClassifyPage />} />
                <Route path="/detect"   element={<ProtectedRoute><DetectPage /></ProtectedRoute>} />
                <Route path="/history"  element={<ProtectedRoute><HistoryPage /></ProtectedRoute>} />
                <Route path="/profile"  element={<ProtectedRoute><ProfilePage /></ProtectedRoute>} />
              </Routes>
            </main>
          </BrowserRouter>
        </AuthProvider>
      </LangProvider>
    </ThemeProvider>
  );
}
